CREATE TABLE IF NOT EXISTS withdraw (id SERIAL PRIMARY KEY, username VARCHAR(100) NOT NULL, amount DECIMAL NOT NULL, withdraw_type VARCHAR(20) DEFAULT ''''bank'''', bank_name VARCHAR(200) DEFAULT ''''''', account_name VARCHAR(200) DEFAULT ''''''', account_number VARCHAR(200) DEFAULT ''''''', fps_account VARCHAR(200) DEFAULT ''''''', status VARCHAR(20) DEFAULT ''''pending'''', admin_note TEXT, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP);